    signatureDishes: [
      { name: 'Souvlakia', description: 'Marinated pork or chicken threaded onto skewers and grilled over charcoal, served with flatbread and yogurt — the Cypriot equivalent of fast food, eaten everywhere.' },
      { name: 'Kleftiko', description: 'Lamb marinated in wine, lemon, and spices then slow-baked in a sealed clay pot until meltingly tender — named for the mountain bandits (kleftes) who cooked it in underground pits.' },
      { name: 'Loukoumades', description: 'Deep-fried honey doughnuts dusted with cinnamon — a sweet shared across Cyprus regardless of communal division.' },
    ],
